code = """import json, re
from collections import defaultdict
with open(var_call_D4rq9cs4gFNTl4lSdqgfzKOa, 'r', encoding='utf-8') as f:
    unc_rows = json.load(f)
with open(var_call_IItaqV0SEoPNDJAoMxeGoSEA, 'r', encoding='utf-8') as f:
    all_rows = json.load(f)

# helper to extract digits from publication number
def digits(s):
    return ''.join(re.findall(r'\d+', (s or '')))

# build set of UNC numeric ids from unc_rows: attempt to get publication numbers from Patents_info and from 'cited mapping' earlier
unc_nums = set()
for r in unc_rows:
    info = r.get('Patents_info','')
    # find any token containing digits and letters
    m = re.search(r'([A-Z]{1,3}-\d+[-A-Z0-9]*)', info.upper())
    if m:
        unc_nums.add(digits(m.group(1)))
    else:
        m2 = re.search(r'(\d{4,})', info)
        if m2:
            unc_nums.add(m2.group(1))

# also try to find from citation field inside unc_rows (if any)
for r in unc_rows:
    cit = r.get('citation','[]')
    try:
        cites = json.loads(cit)
    except Exception:
        cites = []
    for c in cites:
        unc_nums.add(digits(c.get('publication_number','')))

unc_nums = set(x for x in unc_nums if x)

assignee_to_codes = defaultdict(set)

for r in all_rows:
    try:
        citations = json.loads(r.get('citation','[]'))
    except Exception:
        citations = []
    cites_unc = False
    for c in citations:
        pub = c.get('publication_number','')
        if not pub:
            continue
        if digits(pub) in unc_nums:
            cites_unc = True
            break
    if cites_unc:
        info = r.get('Patents_info','')
        info_up = info.upper()
        # extract assignee heuristically
        assignee = None
        for sep in [' HOLDS', ' IS ASSIGNED TO', ' IS OWNED BY', ' OWNS', ' HAS THE', ' WITH PUB.', ' WITH PUBLICATION NUMBER', ' FILES', ' FILED']:
            if sep in info_up:
                assignee = info_up.split(sep)[0].strip()
                break
        if not assignee:
            m = re.match(r'^([A-Z0-9 &,.\-]+)', info_up)
            assignee = m.group(1).strip() if m else info_up.split(' ')[0]
        if 'UNIV CALIFORNIA' in assignee:
            continue
        # extract primary CPC codes
        try:
            cpc_list = json.loads(r.get('cpc','[]'))
        except Exception:
            cpc_list = []
        primary = [e.get('code') for e in cpc_list if e.get('first')]
        if not primary and cpc_list:
            primary = [cpc_list[0].get('code')]
        for code in primary:
            if code:
                assignee_to_codes[assignee].add(code)

# prepare output
out_list = []
all_codes = set()
for a, codes in assignee_to_codes.items():
    codes_list = sorted(list(codes))
    out_list.append({'assignee': a, 'primary_cpc_codes': codes_list})
    all_codes.update(codes_list)

res = {'assignee_codes': out_list, 'all_codes': sorted(list(all_codes)), 'unc_nums_count': len(unc_nums)}
print('__RESULT__:')
print(json.dumps(res))"""

